#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI MAXN=5e5+5;
vector<PII>q[MAXN];
int n,s,ans;
bool vis[MAXN];
int quickpow(int a,int b)
{
	int res=1;
	wh(b)
	{
		if(b&1)res=res*a;
		a=a*a;
		b>>=1;
	}
	return res;
}
int dfs(int nod,int tim)
{
	vis[nod]=1;
	int mx=0,o,cnt=0;
	FOR(i,0,q[nod].size()-1)
	{
		int son=q[nod][i].fst,w=q[nod][i].snd;
		if(!vis[son])
		{
			o=dfs(son,tim+w);

			if(o<mx)ans+=mx-o;
			if(o>mx)
			{
				ans+=cnt*(o-mx);
				mx=o;
			}
			++cnt;
		}
	}
	if(cnt==0)
	{
		return tim;
	}
	return mx;
}
signed main(void)
{
	IOS
	cin>>n>>s;
	FOR(i,2,n)
	{
		int u,v,w;
		cin>>u>>v>>w;
		q[u].pb(mk(v,w));
		q[v].pb(mk(u,w));
	}
	dfs(s,0);
	cout<<ans;
	return false;
}
